import math


def epsilon_parameter(f_y: float) -> float:
    """Calculate the epsilon parameter based on yield strength.

    Args:
        f_y (float): Yield strength in MPa.

    Returns:
        float: The value of epsilon = sqrt(235 / f_y).
    """
    return math.sqrt(235.0 / f_y)


def checked_is_required(
    hw: float, t: float, f_y: float, eta: float = 1.20, k_tau: float = None
) -> bool:
    """Determine if a shear buckling check is required for the web.

    EN 1993-1-5:2006. Section 5.1 (2).

    Args:
        hw (float): Clear web depth between flanges in mm.
        t (float): Thickness of the web plate in mm.
        f_y (float): Yield strength of the web in MPa.
        eta (float): Factor for shear resistance. Recommended 1.20 for <= S460.
        k_tau (float, optional): Shear buckling coefficient for stiffened webs.
            If None, the web is treated as unstiffened.

    Returns:
        bool: True if a shear buckling check is required, False otherwise.
    """
    epsilon = epsilon_parameter(f_y)
    slenderness = hw / t

    if k_tau is None:
        # Unstiffened web
        limit = (72 / eta) * epsilon
    else:
        # Stiffened web
        limit = (31 / eta) * epsilon * math.sqrt(k_tau)

    return slenderness > limit


def lambda_w(
    hw: float, t: float, f_y: float, k_tau: float = None, tau_cr: float = None
) -> float:
    """Calculate the modified web slenderness for shear buckling.
    - If tau_cr is provided, the general formula (5.3) is used
    - Otherwise,
        - transverse stiffeners at supports only, do not provide k_tau - Eq. (5.5)
        - transverse stiffeners at supports and intermediate transverse or longitudinal
          stiffeners or both. k_tau is required - Eq. (5.6) / (5.7)


    EN 1993-1-5:2006. Eq. (5.3), (5.5), (5.6), and (5.7).

    Args:
        hw (float): Clear web depth (or subpanel depth hwi) in mm.
        t (float): Web thickness in mm.
        f_y (float): Yield strength in MPa.
        k_tau (float, optional): Minimum shear buckling coefficient.
        tau_cr (float, optional): Elastic critical shear buckling stress in MPa.
        If provided, the general formula (5.3) is used instead of (5.5), (5.6)/(5.7).

    Returns:
        float: The modified web slenderness lambda_w_bar.
    """
    if tau_cr is not None:
        # General formula Eq. (5.3)
        return 0.76 * math.sqrt(f_y / tau_cr)

    epsilon = epsilon_parameter(f_y)
    if k_tau is None:
        # Unstiffened web (transverse stiffeners at supports only) Eq. (5.5)
        return hw / (86.4 * t * epsilon)
    else:
        # Stiffened web or subpanel Eq. (5.6) / (5.7)
        return hw / (37.4 * t * epsilon * math.sqrt(k_tau))


def tau_cr(k_tau: float, sigma_E: float) -> float:
    """Calculate the critical shear buckling stress.

    EN 1993-1-5:2006. Eq. (5.4).

    Args:
        k_tau (float): Shear buckling coefficient.
        sigma_E (float): Euler reference stress for plate buckling in MPa.

    Returns:
        float: The critical shear buckling stress tau_cr in MPa.
    """
    return k_tau * sigma_E


def chi_w(lambda_w: float, eta: float = 1.20, rigid_end_post: bool = True) -> float:
    """Determine the contribution factor of the web to shear buckling resistance.

    EN 1993-1-5:2006. Table 5.1.

    Args:
        lambda_w (float): Modified web slenderness.
        eta (float): Factor for shear resistance. Default 1.20.
        rigid_end_post (bool): True for rigid end post, False for non-rigid.

    Returns:
        float: The factor chi_w.
    """
    if rigid_end_post:
        if lambda_w < 0.83 / eta:
            return eta
        elif lambda_w < 1.0:
            return 0.83 / lambda_w
        else:
            return 1.37 / (0.7 + lambda_w)
    else:
        if lambda_w < 0.83 / eta:
            return eta
        else:
            return 0.83 / lambda_w


def Vbw_Rd(
    chi_w: float, f_yw: float, hw: float, t: float, gamma_M1: float = 1.1
) -> float:
    """Calculate the design shear resistance contribution from the web.

    EN 1993-1-5:2006. Eq. (5.2).

    Args:
        chi_w (float): Contribution factor from the web.
        f_yw (float): Yield strength of the web in MPa.
        hw (float): Clear web depth in mm.
        t (float): Web thickness in mm.
        gamma_M1 (float): Partial factor for resistance. Default 1.1.

    Returns:
        float: The design shear resistance from the web in N.
    """
    return (chi_w * f_yw * hw * t) / (math.sqrt(3) * gamma_M1)


def Vbf_Rd(
    M_Ed: float,
    M_f_Rd_gross: float,
    bf: float,
    tf: float,
    f_yf: float,
    a: float,
    hw: float,
    t_w: float,
    f_yw: float,
    gamma_M1: float = 1.0,
    N_Ed: float = 0.0,
    Af1: float = 0.0,
    Af2: float = 0.0,
    gamma_M0: float = 1.0,
) -> float:
    """Calculate the design shear resistance contribution from the flanges.

    EN 1993-1-5:2006. Eq. (5.8) and (5.9), including axial force reduction.

    Args:
        M_Ed (float): Design bending moment in N*mm. (positive compression)
        M_f_Rd_gross (float): Moment of resistance of the cross section consisting
            of flanges only (unreduced for axial force) in N*mm.
        bf (float): Width of the flange in mm.
        tf (float): Thickness of the flange in mm.
        f_yf (float): Yield strength of the flange in MPa.
        a (float): Distance between transverse stiffeners in mm.
        hw (float): Clear web depth in mm.
        t_w (float): Thickness of the web plate in mm.
        f_yw (float): Yield strength of the web in MPa.
        gamma_M1 (float): Partial factor for resistance. Default 1.0.
        N_Ed (float, optional): Design axial force in N.
        Af1 (float, optional): Area of the top flange in mm2.
        Af2 (float, optional): Area of the bottom flange in mm2.
        gamma_M0 (float, optional): Partial factor for resistance. Default 1.0.

    Returns:
        float: The design shear resistance from the flanges in N.
    """
    # Reduce M_f_Rd if axial force is present (Section 5.4 (2) Eq. (5.9))
    M_f_Rd = M_f_Rd_gross
    if N_Ed != 0:
        reduction_factor = 1 - abs(N_Ed) / (((Af1 + Af2) * f_yf) / gamma_M0)
        M_f_Rd *= max(0, reduction_factor)

    if M_Ed >= M_f_Rd:
        return 0.0

    # Calculate parameter c
    c = a * (0.25 + (1.6 * bf * tf**2 * f_yf) / (t_w * hw**2 * f_yw))

    # Calculate flange contribution (Eq. 5.8)
    term_moment = 1 - (M_Ed / M_f_Rd) ** 2
    return (bf * tf**2 * f_yf) / (c * gamma_M1) * term_moment


def Vb_Rd(
    Vbw_Rd_val: float,
    Vbf_Rd_val: float,
    eta: float,
    f_yw: float,
    hw: float,
    t: float,
    gamma_M1: float = 1.0,
) -> float:
    """Calculate the total design shear resistance.

    EN 1993-1-5:2006. Eq. (5.1).

    Args:
        Vbw_Rd_val (float): Contribution from the web in N.
        Vbf_Rd_val (float): Contribution from the flanges in N.
        eta (float): Factor for shear resistance.
        f_yw (float): Yield strength of the web in MPa.
        hw (float): Clear web depth in mm.
        t (float): Web thickness in mm.
        gamma_M1 (float): Partial factor for resistance. Default 1.0.

    Returns:
        float: The total design shear resistance Vb_Rd in N.
    """
    total = Vbw_Rd_val + Vbf_Rd_val
    limit = (eta * f_yw * hw * t) / (math.sqrt(3) * gamma_M1)
    return min(total, limit)


def sigma_E(E: float, t: float, b: float, nu: float = 0.3) -> float:
    """Calculate the Euler reference stress for plate buckling.

    EN 1993-1-5:2006. Annex A.1, Eq. (A.1).
    Note: For web panels, 'b' should be replaced by 'hw'.

    Args:
        E (float): Modulus of elasticity in MPa.
        t (float): Thickness of the plate in mm.
        b (float): Width of the plate (or clear web depth hw) in mm.
        nu (float, optional): Poisson's ratio. Default value = 0.3 for steel.

    Returns:
        float: The elastic critical plate buckling stress sigma_E in MPa.
    """
    return (math.pi**2 * E * t**2) / (12 * (1 - nu**2) * b**2)


def k_tau(
    a: float, hw: float, t: float, I_sl: float = 0.0, n_stiffeners: int = 0
) -> float:
    """Calculate the shear buckling coefficient for a web panel.

    EN 1993-1-5:2006. Annex A.3, Eq. (A.5) and (A.6).

    Args:
        a (float): Distance between transverse stiffeners in mm.
        hw (float): Clear web depth between flanges in mm.
        t (float): Web thickness in mm.
        I_sl (float, optional): Second moment of area of the longitudinal
            stiffener(s). Per 5.3(4), this should be reduced to 1/3 of its
            actual value for this calculation.
            Default value = 0.0.
        n_stiffeners (int, optional): Number of longitudinal stiffeners.
            Default value = 0.

    Returns:
        float: The shear buckling coefficient k_tau.
    """
    alpha = a / hw
    gamma = I_sl / (t**3 * hw)

    # Case for 1 or 2 longitudinal stiffeners with aspect ratio alpha < 3.
    # EN 1993-1-5:2006. Annex A.3, Eq. (A.6).
    if 0 < n_stiffeners <= 2 and alpha < 3.0:
        return 4.1 + (6.3 + 0.18 * gamma) / (alpha**2) + 2.22 * (gamma ** (1 / 3))

    # General case.
    # EN 1993-1-5:2006. Annex A.3, Eq. (A.5).
    # Applies if unstiffened, > 2 stiffeners, or 1-2 stiffeners with alpha >= 3.
    k_tau_l = 0.0
    if I_sl > 0:
        # Eq. (A.5) contribution from longitudinal stiffeners.
        k_tau_l_calc = 9 * (1 / alpha) ** 2 * (gamma**3) ** (1 / 4)
        # Minimum value check for k_tau_l.
        limit = (2.1 / t) * (I_sl / hw) ** (1 / 3)
        k_tau_l = max(k_tau_l_calc, limit)

    if alpha >= 1.0:
        # Eq. (A.5) for aspect ratio alpha >= 1.
        return 5.34 + 4.00 * (1 / alpha) ** 2 + k_tau_l
    else:
        # Eq. (A.5) for aspect ratio alpha < 1.
        return 4.00 + 5.34 * (1 / alpha) ** 2 + k_tau_l
